const profiles = $('Split Into Individual Profiles').all();
const sheetRows = $('Read Emails from Google Sheet').all().map(i => i.json);

function normalizeUrl(url) {
  if (!url) return '';
  return url.toLowerCase().replace('https://', '').replace('http://', '').replace('www.', '')
    .replace(/[a-z]{2}\.linkedin\.com/, 'linkedin.com').split('?')[0].replace(/\/$/, '').trim();
}

const emailMap = {};
for (const row of sheetRows) {
  const urlKey = Object.keys(row).find(k => k.toLowerCase().includes('profile') && k.toLowerCase().includes('url'));
  const emailKey = Object.keys(row).find(k => k.toLowerCase().includes('email'));
  const url = normalizeUrl(urlKey ? row[urlKey] : '');
  const email = (emailKey ? row[emailKey] : '').trim();
  if (url && email && email.includes('@')) emailMap[url] = email;
}

const results = [];
for (const item of profiles) {
  const p = { ...item.json };
  const currentUrl = normalizeUrl(p.url || p.linkedin_url || '');
  const email = (p.email || '').toLowerCase();
  if (!email || email.includes('restricted') || !email.includes('@')) {
    const sheetEmail = emailMap[currentUrl];
    if (sheetEmail) { p.email = sheetEmail; p.email_source = 'google_sheet'; }
  }
  results.push({ json: p });
}
return results;

const existingLeads = $('Fetch Existing Leads from DB').all();
const existingUrls = new Set(existingLeads.map(l => (l.json.linkedin_url || '').toLowerCase()));

const currentItems = $('Fill Missing Emails from Sheet').all();
const results = [];

for (const item of currentItems) {
  const p = item.json;
  const url = (p.url || p.linkedin_url || '').toLowerCase();
  const email = (p.email || '').toLowerCase();

  if (!email || !email.includes('@') || email.includes('restricted')) continue;

  const alreadyInDb = existingUrls.has(url);

  if (!alreadyInDb) {
    p.is_new_lead = true; // Force True if not in DB
    results.push({ json: p });
  } else if (alreadyInDb && p.is_new_lead === false) {
    results.push({ json: p });
  }
}

return results;

